    const e = (startLevel & 1) ? 'R' : 'L';
    const sor = e;
    // W1-W7
    let lastType = sor;
    for (let i = 0; i < len; i++) {
        if (types[i] === 'NSM')
            types[i] = lastType;
        else
            lastType = types[i];
    }
    lastType = sor;
    for (let i = 0; i < len; i++) {
        const t = types[i];
        if (t === 'EN')
            types[i] = lastType === 'AL' ? 'AN' : 'EN';
        else if (t === 'R' || t === 'L' || t === 'AL')
            lastType = t;
    }
    for (let i = 0; i < len; i++) {
        if (types[i] === 'AL')
            types[i] = 'R';
    }
    for (let i = 1; i < len - 1; i++) {
        if (types[i] === 'ES' && types[i - 1] === 'EN' && types[i + 1] === 'EN') {
            types[i] = 'EN';
        }
        if (types[i] === 'CS' &&
            (types[i - 1] === 'EN' || types[i - 1] === 'AN') &&
            types[i + 1] === types[i - 1]) {
            types[i] = types[i - 1];
        }
    }
    for (let i = 0; i < len; i++) {
        if (types[i] !== 'EN')
            continue;
        let j;
        for (j = i - 1; j >= 0 && types[j] === 'ET'; j--)
            types[j] = 'EN';
        for (j = i + 1; j < len && types[j] === 'ET'; j++)
            types[j] = 'EN';
    }
    for (let i = 0; i < len; i++) {
        const t = types[i];
        if (t === 'WS' || t === 'ES' || t === 'ET' || t === 'CS')
            types[i] = 'ON';
    }
    lastType = sor;
    for (let i = 0; i < len; i++) {
        const t = types[i];
        if (t === 'EN')
            types[i] = lastType === 'L' ? 'L' : 'EN';
        else if (t === 'R' || t === 'L')
            lastType = t;
    }
